func devbuildRerunUsage() {
	fmt.Fprintf(os.Stderr, `%[1]s [flags] devbuild rerun -id INT -dryrun BOOL

Rerun devbuild
    -id INT: ID of build
    -dryrun BOOL: 

Example:
    %[1]s devbuild rerun --id 1 --dryrun true
`, os.Args[0])
}

func devbuildIngestEventUsage() {
	fmt.Fprintf(os.Stderr, `%[1]s [flags] devbuild ingest-event -body JSON -datacontenttype STRING -id STRING -source STRING -type STRING -specversion STRING -time STRING

Ingest a CloudEvent for build events
    -body JSON: 
    -datacontenttype STRING: 
    -id STRING: 
    -source STRING: 
    -type STRING: 
    -specversion STRING: 
    -time STRING: 

Example:
    %[1]s devbuild ingest-event --body '{
      "data": {
         "buildId": "123",
         "duration": 3600,
         "status": "success",
         "version": "v6.1.0"
      },
      "dataschema": "https://example.com/registry/schemas/build-event.json",
      "subject": "tidb-build-123"
   }' --datacontenttype "Ad aut iure autem dolores quibusdam et." --id "f81d4fae-7dec-11d0-a765-00a0c91e6bf6" --source "/jenkins/build" --type "com.pingcap.build.complete" --specversion "1.0" --time "2022-10-01T12:00:00Z"
`, os.Args[0])
}

// hotfixUsage displays the usage of the hotfix command and its subcommands.
func hotfixUsage() {
	fmt.Fprintf(os.Stderr, `The hotfix service provides operations to manage hotfix git tags.
Usage:
    %[1]s [globalflags] hotfix COMMAND [flags]

COMMAND:
    bump-tag-for-tidbx: Create a hot fix git tag for a GitHub repository
    query-tag-of-tidbx: Query tag info of tidbx repo

Additional help:
    %[1]s hotfix COMMAND --help
`, os.Args[0])
}
func hotfixBumpTagForTidbxUsage() {
	fmt.Fprintf(os.Stderr, `%[1]s [flags] hotfix bump-tag-for-tidbx -body JSON

Create a hot fix git tag for a GitHub repository
    -body JSON: 

Example:
    %[1]s hotfix bump-tag-for-tidbx --body '{
      "author": "abc@test.com",
      "branch": "release-8.5",
      "commit": "abc123def456",
      "meta": {
         "ops_req": {
            "applicant": "tidb",
            "change_id": "c1",
            "release_id": "r1"
         }
      },
      "repo": "pingcap/tidb"
   }'
`, os.Args[0])
}

func hotfixQueryTagOfTidbxUsage() {
	fmt.Fprintf(os.Stderr, `%[1]s [flags] hotfix query-tag-of-tidbx -repo STRING -tag STRING

Query tag info of tidbx repo
    -repo STRING: 
    -tag STRING: 

Example:
    %[1]s hotfix query-tag-of-tidbx --repo "pingcap/tidb" --tag "v26.3.1-nextgen"
`, os.Args[0])
}
